+    #[test]
+    fn linechart_single_x_range_expands() {
+        // All points have x=5 => x_range=0 => expanded to [-1,1] around midpoint.
+        let data: Vec<(f64, f64)> = vec![(5.0, 0.0), (5.0, 10.0)];
+        let series = vec![Series::new("s", &data, PackedRgba::WHITE)];
