+        let mut pool = GraphemePool::new();
+        let mut frame = Frame::new(20, 10, &mut pool);
+        LineChart::new(series).render(area, &mut frame);
+        // Should draw axis without panic.
+        assert_eq!(char_at(&frame.buffer, 0, 0), Some('│'));
+    }
