+    #[test]
+    fn linechart_with_multiple_y_labels() {
+        let data: Vec<(f64, f64)> = vec![(0.0, 0.0), (10.0, 10.0)];
+        let series = vec![Series::new("s", &data, PackedRgba::WHITE)];
